/**
 * pushService.ts — Unified Web Push Notification service
 *
 * Supports three providers controlled by VITE_PUSH_PROVIDER:
 *
 *   'fcm'   — Firebase Cloud Messaging
 *              • Registers firebase-messaging SW
 *              • Gets FCM token via Firebase SDK getToken()
 *              • Posts token to BFF → Notification microservice FcmDispatcher
 *              • Background push delivered via FCM → SW push event
 *
 *   'vapid' — Self-hosted VAPID
 *              • Registers service worker /sw.js
 *              • Fetches VAPID public key from BFF GET /push/vapid-key
 *              • Calls pushManager.subscribe({ applicationServerKey })
 *              • Posts PushSubscription to BFF → VapidPushService
 *              • Background push delivered by BFF WebPush → SW push event
 *
 *   'none'  — No Web Push; SignalR foreground-only (default)
 *
 * Usage:
 *   const push = getPushService();
 *   await push.init();          // on login
 *   await push.deregister();    // on logout
 */

import { apiClient } from '@linm-soft/common-components';

// ── Types ────────────────────────────────────────────────────────────────────

export type PushProvider = 'fcm' | 'vapid' | 'none';

interface VapidKeyResponse {
  publicKey: string;
  enabled: boolean;
}

// ── Provider detection ────────────────────────────────────────────────────────

/** Reads VITE_PUSH_PROVIDER and returns the current push provider. */
export function getPushProvider(): PushProvider {
  const raw = import.meta.env.VITE_PUSH_PROVIDER as string | undefined;
  if (raw === 'fcm' || raw === 'vapid') return raw;
  return 'none';
}

// ── Service Worker registration ───────────────────────────────────────────────

let _swRegistration: ServiceWorkerRegistration | null = null;

async function registerSW(): Promise<ServiceWorkerRegistration | null> {
  if (!('serviceWorker' in navigator)) {
    console.warn('[Push] Service Workers not supported in this browser');
    return null;
  }
  if (_swRegistration) return _swRegistration;

  try {
    const base = ((import.meta.env.BASE_URL as string) || '/').replace(/\/$/, '');
    _swRegistration = await navigator.serviceWorker.register(`${base}/sw.js`);
    console.log('[Push] Service Worker registered:', _swRegistration.scope);
    return _swRegistration;
  } catch (err) {
    console.error('[Push] Service Worker registration failed:', err);
    return null;
  }
}

// ── FCM provider ──────────────────────────────────────────────────────────────

interface FcmConfigResponse {
  apiKey:             string;
  authDomain?:        string;
  projectId?:         string;
  messagingSenderId?: string;
  appId?:             string;
  vapidKey:           string;
  enabled:            boolean;
}

async function initFcm(): Promise<void> {
  try {
    // Fetch Firebase config from BFF — same pattern as VAPID.
    // No Firebase env vars needed on the frontend; all credentials live in the
    // Notification service and are exposed via GET /push/fcm-config.
    const resp    = await apiClient.get<{ data: FcmConfigResponse }>('/push/fcm-config');
    const fcmData = (resp as unknown as { data: FcmConfigResponse })?.data;

    if (!fcmData?.enabled || !fcmData?.apiKey || !fcmData?.vapidKey) {
      console.warn('[Push:FCM] FCM not enabled or config missing on server — skipping FCM init');
      return;
    }

    // Dynamic import so Firebase SDK is only loaded when FCM is enabled
    const { initializeApp, getApps, getApp } = await import('firebase/app');
    const { getMessaging, getToken }          = await import('firebase/messaging');

    const firebaseConfig = {
      apiKey:            fcmData.apiKey,
      authDomain:        fcmData.authDomain,
      projectId:         fcmData.projectId,
      messagingSenderId: fcmData.messagingSenderId,
      appId:             fcmData.appId,
    };

    // Prevent re-initializing on hot reload
    const app       = getApps().length ? getApp() : initializeApp(firebaseConfig);
    const messaging = getMessaging(app);

    // Use our custom SW (not firebase-messaging-sw.js) as the SW registration
    const swReg = await registerSW();
    if (!swReg) return;

    const token = await getToken(messaging, {
      vapidKey: fcmData.vapidKey,
      serviceWorkerRegistration: swReg,
    });

    if (!token) {
      console.warn('[Push:FCM] getToken returned empty — notification permission may be denied');
      return;
    }

    // Register token with BFF → Notification microservice
    await apiClient.post('/push/device-tokens', {
      platform: 'web',
      token,
      deviceId: `web-${navigator.userAgent.slice(0, 40)}`,
    });

    console.log('[Push:FCM] Token registered ✅');
  } catch (err) {
    console.error('[Push:FCM] init failed:', err);
  }
}

async function deregisterFcm(): Promise<void> {
  try {
    const { getApps, getApp } = await import('firebase/app');
    const { getMessaging, deleteToken } = await import('firebase/messaging');
    if (!getApps().length) return;

    const messaging = getMessaging(getApp());
    await deleteToken(messaging);
    console.log('[Push:FCM] Token deleted');
  } catch {
    // Ignore — not critical on logout
  }
}

// ── VAPID provider ────────────────────────────────────────────────────────────

/** Convert a base64url string to Uint8Array (required by pushManager.subscribe). */
function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64  = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const raw     = window.atob(base64);
  return Uint8Array.from([...raw].map((c) => c.charCodeAt(0)));
}

async function initVapid(): Promise<void> {
  try {
    // 1. Register SW
    const swReg = await registerSW();
    if (!swReg) return;

    // 2. Get VAPID public key from BFF
    // Server returns ApiResponse<VapidKeyResponse> — data is nested under .data
    const keyResp = await apiClient.get<{ data: VapidKeyResponse }>('/push/vapid-key');
    const vapidData = (keyResp as unknown as { data: VapidKeyResponse })?.data;
    if (!vapidData?.enabled || !vapidData?.publicKey) {
      console.warn('[Push:VAPID] VAPID not enabled or public key not configured on server — skipping');
      return;
    }
    const vapidPublicKey = vapidData.publicKey;

    // 3. Check for existing subscription; create if none
    let subscription = await swReg.pushManager.getSubscription();
    const isNewSubscription = !subscription;
    if (!subscription) {
      subscription = await swReg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(vapidPublicKey).buffer as ArrayBuffer,
      });
    }

    // 4. Register subscription with BFF only when it's brand-new.
    //    Re-registering the same endpoint on every page load can stack up
    //    duplicate DB rows and cause the server to deliver multiple pushes.
    if (!isNewSubscription) {
      console.log('[Push:VAPID] Existing subscription found — skipping server registration (already registered)');
      return;
    }
    const keys = subscription.toJSON().keys as { p256dh: string; auth: string } | undefined;
    if (!keys) {
      console.warn('[Push:VAPID] Subscription has no keys — skipping');
      return;
    }

    await apiClient.post('/push/subscriptions', {
      endpoint:  subscription.endpoint,
      p256dhKey: keys.p256dh,
      authKey:   keys.auth,
    });

    console.log('[Push:VAPID] Subscription registered ✅');
  } catch (err) {
    console.error('[Push:VAPID] init failed:', err);
  }
}

async function deregisterVapid(): Promise<void> {
  try {
    if (!('serviceWorker' in navigator)) return;
    // Use getRegistration() instead of .ready — .ready waits indefinitely
    // if no SW is active (e.g. fresh incognito tab), causing logout to hang.
    const swReg = await navigator.serviceWorker.getRegistration();
    if (!swReg) return; // No SW registered — nothing to deregister
    const sub = await swReg.pushManager.getSubscription();
    if (sub) {
      await apiClient.delete('/push/subscriptions', {
        data: { endpoint: sub.endpoint },
      });
      await sub.unsubscribe();
      console.log('[Push:VAPID] Subscription removed');
    }
  } catch {
    // Ignore — not critical on logout
  }
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Initialise push notifications for the current session.
 * Call once after login AND after Notification.requestPermission() is granted.
 *
 * Safe to call multiple times — idempotent per session.
 */
export async function initPushNotifications(): Promise<void> {
  const provider = getPushProvider();
  console.log('[Push] Provider:', provider);

  if (provider === 'fcm')   { await initFcm();   return; }
  if (provider === 'vapid') { await initVapid(); return; }
  // 'none' — no-op
}

/**
 * Deregister push subscription and delete token.
 * Call on logout so the user stops receiving push notifications on this device.
 */
export async function deregisterPushNotifications(): Promise<void> {
  const provider = getPushProvider();
  if (provider === 'fcm')   { await deregisterFcm();   return; }
  if (provider === 'vapid') { await deregisterVapid(); return; }
}
