import React, { useEffect } from 'react';
import { Provider, useDispatch } from 'react-redux';
import { fetchUnreadCount, signalRService } from '@linm-soft/common-components';
import { notificationStore } from '../store/store';
import type { NotificationDispatch } from '../store/store';

const NotificationParcelEffects: React.FC = () => {
  const dispatch = useDispatch<NotificationDispatch>();

  useEffect(() => {
    dispatch(fetchUnreadCount());
  }, [dispatch]);

  useEffect(() => {
    const handler = () => {
      if (document.visibilityState === 'visible') dispatch(fetchUnreadCount());
    };
    document.addEventListener('visibilitychange', handler);
    return () => document.removeEventListener('visibilitychange', handler);
  }, [dispatch]);

  useEffect(() => signalRService.onReconnected(() => dispatch(fetchUnreadCount())), [dispatch]);

  return null;
};

export const NotificationParcelShell: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <Provider store={notificationStore}>
    <NotificationParcelEffects />
    {children}
  </Provider>
);
